  builder_.add_BUYER_ENCRYPTION_PUBKEY(BUYER_ENCRYPTION_PUBKEY);
  builder_.add_BUYER_PEER_ID(BUYER_PEER_ID);
  builder_.add_TIER_NAME(TIER_NAME);
  builder_.add_LISTING_ID(LISTING_ID);
